"use client";

import BlogCard from "../BlogCard";
import { motion } from "framer-motion";

interface FeaturedBlogsProps {
    blogs: any[];
}

const container = {
    hidden: { opacity: 0 },
    show: {
        opacity: 1,
        transition: {
            staggerChildren: 0.2
        }
    }
};

const item = {
    hidden: { opacity: 0, y: 30 },
    show: { opacity: 1, y: 0, transition: { duration: 0.6 } }
};

export default function FeaturedBlogs({ blogs }: FeaturedBlogsProps) {
    return (
        <section className="py-24 md:py-32 bg-white relative">
            <div className="max-w-7xl mx-auto px-6">
                <motion.div
                    initial={{ opacity: 0, y: 20 }}
                    whileInView={{ opacity: 1, y: 0 }}
                    viewport={{ once: true }}
                    className="flex flex-col md:flex-row justify-between items-start md:items-end mb-20 gap-8"
                >
                    <div>
                        <div className="text-blue-600 font-bold text-sm tracking-widest uppercase mb-4">Latest Insights</div>
                        <h2 className="text-4xl md:text-6xl font-heading font-black text-zinc-900 mb-6">
                            Featured <span className="italic font-accent text-zinc-400">Stories</span>
                        </h2>
                        <p className="text-zinc-500 font-body text-lg max-w-xl leading-relaxed">
                            Carefully curated articles about the intersection of design, technology, and the future of the web.
                        </p>
                    </div>
                    <motion.a
                        whileHover={{ scale: 1.05 }}
                        whileTap={{ scale: 0.95 }}
                        href="/blog"
                        className="px-8 py-3 bg-zinc-50 border border-zinc-200 rounded-full font-body font-bold text-zinc-900 hover:bg-zinc-900 hover:text-white transition-all duration-300"
                    >
                        Explore All Posts
                    </motion.a>
                </motion.div>

                {blogs.length > 0 ? (
                    <motion.div
                        variants={container}
                        initial="hidden"
                        whileInView="show"
                        viewport={{ once: true }}
                        className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-10"
                    >
                        {blogs.map((blog) => (
                            <motion.div variants={item} key={blog._id}>
                                <BlogCard
                                    title={blog.title}
                                    excerpt={blog.excerpt}
                                    category={blog.categories?.[0]?.title || "Article"}
                                    date={new Date(blog.publishedAt).toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' })}
                                    slug={blog.slug}
                                    mainImage={blog.mainImage}
                                />
                            </motion.div>
                        ))}
                    </motion.div>
                ) : (
                    <div className="text-center py-32 bg-zinc-50 rounded-[4rem] border border-zinc-100 overflow-hidden relative">
                        <div className="absolute inset-0 bg-grid opacity-50" />
                        <div className="relative z-10">
                            <p className="text-2xl font-heading font-bold text-zinc-400">Preparing fresh content...</p>
                            <p className="text-zinc-500 mt-2">Check back in a bit or explore the Studio.</p>
                        </div>
                    </div>
                )}
            </div>
        </section>
    );
}
